module top_module(busA, busB, busXOR);input [7:0] busA;
input [7:0] busB;
output [7:0] busXOR;

wire [7:0] temp1, temp2, temp3, temp4;

// XOR operation
  assign busXOR = temp1 ^ temp4;

// Invert the inputs
  assign temp4 = temp2 & temp3;
  assign temp3 = ~busB;

// AND operation
  assign temp2 = ~busA;

// Final XOR operation
  assign temp1 = busA ^ busB;

endmodule
